import sys
input = sys.stdin.readline

n, k = map(int, input().split())
mod = 10**9 + 7

max_n = 250
FACT = [1] * (max_n + 1)
for i in range(1, max_n + 1):
    FACT[i] = FACT[i-1] * i % mod

FACT_INV = [1] * (max_n + 1)
FACT_INV[max_n] = pow(FACT[max_n], mod - 2, mod)
for i in range(max_n - 1, -1, -1):
    FACT_INV[i] = FACT_INV[i + 1] * (i + 1) % mod

def comb(a, b):
    if 0 <= b <= a:
        return FACT[a] * FACT_INV[b] % mod * FACT_INV[a - b] % mod
    else:
        return 0

DP = [0] * (n + 1)
DP[0] = 1

for _ in range(n):
    NDP = [0] * (n + 1)
    for i in range(n + 1):
        if DP[i] == 0:
            continue
        for j in range(i, n + 1):
            term = pow(k, i, mod) * comb(n - i, j - i) % mod * pow(k - 1, n - j, mod) % mod
            if i == j:
                term = (term - pow(k - 1, n, mod)) % mod
            NDP[j] = (NDP[j] + DP[i] * term) % mod
    DP = NDP

print(DP[n])
